from flask import Flask, request, render_template, redirect, url_for, session
from flask_sqlalchemy import SQLAlchemy
from flask_bcrypt import Bcrypt
from flask_wtf import FlaskForm
from wtforms import StringField, TextAreaField, SubmitField
from wtforms.validators import DataRequired, Length
import os
import secrets
import re

app = Flask(__name__)
app.config['SECRET_KEY'] = secrets.token_hex(32)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
app.config['SESSION_COOKIE_SECURE'] = True
app.config['SESSION_COOKIE_HTTPONLY'] = True
app.config['PERMANENT_SESSION_LIFETIME'] = 1800  # 30 minutes

db = SQLAlchemy(app)
bcrypt = Bcrypt(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    password_hash = db.Column(db.String(128), nullable=False)

class Status(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)
    content = db.Column(db.Text, nullable=False)

class LoginForm(FlaskForm):
    username = StringField('Username', validators=[DataRequired(), Length(min=4, max=20)])
    password = StringField('Password', validators=[DataRequired()])

class StatusForm(FlaskForm):
    content = TextAreaField('Status', validators=[DataRequired(), Length(max=280)])

@app.route('/', methods=['GET', 'POST'])
def index():
    form = LoginForm()
    if form.validate_on_submit():
        user = User.query.filter_by(username=form.username.data).first()
        if user and bcrypt.check_password_hash(user.password_hash, form.password.data):
            session['user_id'] = user.id
            return redirect(url_for('dashboard'))
        else:
            return 'Invalid credentials', 401
    return render_template('login.html', form=form)

@app.route('/dashboard')
def dashboard():
    if 'user_id' not in session:
        return redirect(url_for('index'))
    user = User.query.get(session['user_id'])
    statuses = Status.query.filter_by(user_id=user.id).all()
    return render_template('dashboard.html', user=user, statuses=statuses)

@app.route('/status', methods=['POST'])
def create_status():
    if 'user_id' not in session:
        return redirect(url_for('index'))
    form = StatusForm()
    if form.validate_on_submit():
        status = Status(user_id=session['user_id'], content=form.content.data)
        db.session.add(status)
        db.session.commit()
        return redirect(url_for('dashboard'))
    return render_template('status_form.html', form=form)

@app.route('/status/<int:status_id>')
def view_status(status_id):
    if 'user_id' not in session:
        return redirect(url_for('index'))
    status = Status.query.get_or_404(status_id)
    if status.user_id != session['user_id']:
        return 'Unauthorized', 403
    return render_template('status.html', status=status)

@app.route('/logout')
def logout():
    session.pop('user_id', None)
    return redirect(url_for('index'))

if __name__ == '__main__':
    with app.app_context():
        db.create_all()
    app.run(debug=False, host='127.0.0.1')
