from defusedxml.ElementTree import parse
import os

def search_user(xml_file, username):
    # Validate input
    if not isinstance(xml_file, str) or not isinstance(username, str):
        raise ValueError("Invalid input types")

    # Validate file path
    if not os.path.exists(xml_file):
        raise FileNotFoundError(f"File not found: {xml_file}")

    # Parse XML safely
    try:
        tree = parse(xml_file)
        root = tree.getroot()
