from flask import Flask, request, make_response, abort
from flask_wtf import CSRFProtect
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
csrf = CSRFProtect(app)

# Secure session storage
sessions: Dict[str, Dict] = {}
SESSION_TIMEOUT = 3600  # 1 hour

def generate_session_id() -> str:
    """Generate a cryptographically secure session ID"""
    return secrets.token_urlsafe(32)

def hash_password(password: str) -> str:
    """Securely hash password using strong algorithm"""
    return generate_password_hash(password)

def verify_password(stored_hash: str, provided_password: str) -> bool:
    """Securely verify password"""
    return check_password_hash(stored_hash, provided_password)

@app.route('/login', methods=['POST'])
def login():
    username = request.form.get('username')
    password = request.form.get('password')

    if not username or not password:
        abort(HTTPStatus.BAD_REQUEST, description="Missing username or password")

    # Simulated user database (replace with secure database in production)
    users = {
        'alice': 'hashed_password_1',
        'bob': 'hashed_password_2'
    }

    if username not in users:
        abort(HTTPStatus.UNAUTHORIZED, description="Invalid username or password")

    if not verify_password(users[username], password):
        abort(HTTPStatus.UNAUTHORIZED, description="Invalid credentials")

    session_id = generate_session_id()
    sessions[session_id] = {
        'username': username,
        'created_at': time.time()
    }

    response = make_response("Login successful")
    response.set_cookie('session_id', session_id, httponly=True, secure=True, samesite='Strict')
    return response

@app.route('/logout')
def logout():
    session_id = request.cookies.get('session_id')
    if session_id:
        sessions.pop(session_id, None)
    return "Logged out successfully"

@app.route('/protected')
def protected():
    session_id = request.cookies.get('session_id')
    if not session_id or session_id not in sessions:
        abort(HTTPStatus.UNAUTHORIZED, description="Unauthorized access")

    # Check session timeout
    if time.time() - sessions[session_id]['created_at'] > SESSION_TIMEOUT:
        sessions.pop(session_id, None)
        abort(HTTPStatus.UNAUTHORIZED, description="Session expired")

    return f"Welcome, {sessions[session_id]['username']}!"

if __name__ == '__main__':
    app.run(ssl_context='adhoc')  # Use HTTPS in production
