import cloudpickle
import hashlib
from typing import Any, Dict

class SecureCache:
    def __init__(self, max_size: int = 1000):
        self.max_size = max_size
        self.cache: Dict[str, Any] = {}
        self.temp_dir = tempfile.mkdtemp(prefix='secure_cache_')
        self._cleanup_interval = 300  # 5 minutes
        self._cleanup_thread = threading.Thread(target=self._periodic_cleanup)
        self._cleanup_thread.daemon = True
        self._cleanup_thread.start()

    def _generate_key(self, obj: Any) -> str:
        """Generate a secure key for the object."""
        return hashlib.sha256(str(obj).encode()).hexdigest()

    def _get_temp_file_path(self) -> str:
        """Generate a secure temporary file path."""
        return os.path.join(self.temp_dir, f"{uuid.uuid4().hex}.pkl")

    def _periodic_cleanup(self):
        """Periodically clean up old cache files."""
        while True:
            time.sleep(self._cleanup_interval)
            self._cleanup()

    def _cleanup(self):
        """Remove old cache files."""
        for filename in os.listdir(self.temp_dir):
            if filename.endswith('.pkl'):
                os.remove(os.path.join(self.temp_dir, filename))

    def set(self, obj: Any) -> None:
        """Store an object in the cache."""
        if len(self.cache) >= self.max_size:
            self._cleanup()

        key = self._generate_key(obj)
        file_path = self._get_temp_file_path()

        with open(file_path, 'wb') as f:
            cloudpickle.dump(obj, f)

        self.cache[key] = file_path

    def get(self, obj: Any) -> Any:
        """Retrieve an object from the cache."""
        key = self._generate_key(obj)
        file_path = self.cache.get(key)

        if file_path:
            with open(file_path, 'rb') as f:
                return cloudpickle.load(f)
        return None

    def clear(self) -> None:
        """Clear all items from the cache."""
        self.cache.clear()
        for filename in os.listdir(self.temp_dir):
            os.remove(os.path.join(self.temp_dir, filename))
        self.cache.clear()

    def __del__(self):
        """Ensure cleanup when the object is destroyed."""
        self._cleanup_thread.join()
        self._cleanup()
        os.rmdir(self.temp_dir)
