logging.basicConfig(filename='auth.log', level=logging.INFO,
                    format='%(asctime)s - %(levelname)s - %(message)s')

class UserAuth:
    def __init__(self):
        self.users = {}  # In a real system, use a secure database
        self.salt_length = 32
        self.key_length = 32

    def register(self, username: str, password: str) -> bool:
        """Register a new user with a hashed password."""
        if username in self.users:
            return False  # User already exists

        salt = os.urandom(self.salt_length)
        key = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, 100000)
        self.users[username] = {'salt': salt, 'key': key}
        return True

    def authenticate(self, username: str, password: str) -> bool:
        """Authenticate a user and log successful login."""
        if username not in self.users:
            return False  # User not found

        user = self.users[username]
        key = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), user['salt'], 100000)

        if key == user['key']:
            logging.info(f"Successful login: {username}")
            return True
        else:
            return False

    def change_password(self, username: str, old_password: str, new_password: str) -> bool:
        """Change a user's password."""
        if not self.authenticate(username, old_password):
            return False  # Old password is incorrect

        salt = os.urandom(self.salt_length)
        key = hashlib.pbkdf2_hmac('sha256', new_password.encode('utf-8'), salt, 100000)
        self.users[username] = {'salt': salt, 'key': key}
        return True

# Example usage
if __name__ == "__main__":
