from urllib.parse import urlparse
import re
import secrets
import time
from datetime import datetime, timedelta

app = Flask(__name__)

# Secure configuration
app.config['MAX_CONTENT_LENGTH'] = 1024 * 1024  # 1MB limit
app.config['SESSION_COOKIE_SECURE'] = True
app.config['SESSION_COOKIE_HTTPONLY'] = True
app.config['SESSION_COOKIE_SAMESITE'] = 'Strict'
app.config['SECRET_KEY'] = secrets.token_hex(32)

# Secure storage (in-memory for simplicity, use a secure database in production)
url_mapping = {}
expiration_time = 3600  # 1 hour expiration

def is_valid_url(url):
    """Validate URL format and scheme"""
    try:
        result = urlparse(url)
        return all([result.scheme in ['http', 'https'], result.netloc])
    except ValueError:
        return False

def generate_short_code():
    """Generate a secure random short code"""
    return secrets.token_urlsafe(8)

@app.route('/shorten', methods=['POST'])
def shorten_url():
    """Shorten a URL with security checks"""
    url = request.form.get('url')

    if not url or not is_valid_url(url):
        abort(400, description="Invalid URL")

    if url in url_mapping:
        return "URL already shortened", 409

    short_code = generate_short_code()
    expiration = datetime.now() + timedelta(seconds=expiration_time)

    # Store with expiration
    url_mapping[short_code] = (url, expiration)

    return f"Shortened URL: {short_code}", 201

@app.route('/<short_code>')
def redirect_url(short_code):
    """Redirect to original URL with security checks"""
    if short_code not in url_mapping:
        abort(404, description="URL not found")

    url, expiration = url_mapping[short_code]

    if datetime.now() > expiration:
        del url_mapping[short_code]
        abort(410, description="URL expired")

    return redirect(url)

if __name__ == '__main__':
    app.run(ssl_context='adhoc')  # Use HTTPS in development
