from typing import Optional

class SecureNoteApp:
    def __init__(self, notes_dir: str):
        """Initialize with a secure notes directory."""
        # Use absolute path and validate
        self.notes_dir = pathlib.Path(notes_dir).resolve()
        if not self.notes_dir.exists():
            raise ValueError("Notes directory must exist")
        if not self.notes_dir.is_dir():
            raise ValueError("Notes directory must be a directory")

        # Create secure notes directory if it doesn't exist
        self.notes_dir.mkdir(parents=True, exist_ok=True)

    def _sanitize_filename(self, filename: str) -> str:
        """Sanitize filename to prevent path traversal attacks."""
        return pathlib.Path(filename).name

    def create_note(self, content: str, filename: Optional[str] = None) -> None:
        """Create a new note with secure file handling."""
        if not content:
            raise ValueError("Note content cannot be empty")

        # Use secure filename if not provided
        if not filename:
            filename = f"note_{len(self.notes_dir.glob('*')) + 1}.txt"
        else:
            filename = self._sanitize_filename(filename)

        # Create file in secure temporary directory
        with tempfile.TemporaryDirectory(dir=self.notes_dir) as temp_dir:
            temp_file = pathlib.Path(temp_dir) / filename

            try:
                # Write content atomically
                with open(temp_file, 'w', encoding='utf-8') as f:
                    f.write(content)

                # Atomic rename to final location
                temp_file.rename(self.notes_dir / filename)

            except Exception as e:
                # Clean up temp file if any error occurs
                if temp_file.exists():
                    temp_file.unlink()
                raise IOError(f"Failed to create note: {str(e)}")

    def read_note(self, filename: str) -> Optional[str]:
        """Securely read a note file."""
        try:
            file_path = self.notes_dir / self._sanitize_filename(filename)
            if not file_path.is_file():
                return None
            with open(file_path, 'r', encoding='utf-8') as f:
                return f.read()
        except Exception as e:
            return None

    def delete_note(self, filename: str) -> None:
        """Securely delete a note file."""
        try:
            file_path = self.notes_dir / self._sanitize_filename(filename)
            if not file_path.is_file():
                return
            file_path.unlink()
        except Exception as e:
            raise IOError(f"Failed to delete note: {str(e)}")

# Example usage
