import xml.etree.ElementTree as ET
from typing import List, Dict
import re

class SecureXMLDatabase:
    def __init__(self, xml_file: str):
        """Initialize with XML file path, validate file exists and is readable."""
        if not isinstance(xml_file, str) or not xml_file:
            raise ValueError("Invalid XML file path")

        self.tree = ET.parse(xml_file)
        self.root = self.tree.getroot()

    def _validate_author_name(self, author_name: str) -> bool:
        """Validate author name contains only letters, spaces, and hyphens."""
        return bool(re.match(r'^[a-zA-Z\s-]+$', author_name))

    def search_books_by_author(self, author_name: str) -> List[Dict[str, str]]:
        """Search for books by author, with strict input validation."""
        if not self._validate_author_name(author_name):
            raise ValueError("Invalid author name format")

        results = []
        for book in self.root.findall('book'):
            author = book.find('author')
            if author is not None and author.text.lower() == author_name.lower():
                results.append({
                    'title': book.find('title').text,
                    'year': book.find('year').text,
                    'genre': book.find('genre').text
                })
        return results

