import os
import logging
from pathlib import Path
import fcntl
from typing import Optional

class SecureLogger:
    def __init__(self, log_file: str, max_size: int = 10 * 1024 * 1024):
        """Initialize secure logger with strict controls."""
        self.log_file = Path(log_file).resolve()
        self.max_size = max_size
        self.logger = logging.getLogger(__name__)
        self.logger.setLevel(logging.INFO)

        # Ensure log file exists and has proper permissions
        self._setup_log_file()

    def _setup_log_file(self) -> None:
        """Set up log file with secure permissions."""
        try:
            # Create file with secure permissions (read/write for owner only)
            with open(self.log_file, 'a+b') as f:
                os.chmod(self.log_file, 0o600)

            # Set up logging
            handler = logging.FileHandler(self.log_file)
            formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
            handler.setFormatter(formatter)
            self.logger.addHandler(handler)

            # Set up file locking
            fcntl.flock(self.log_file, fcntl.LOCK_EX)
        except Exception as e:
            self.logger.error(f"Failed to setup log file: {str(e)}")
            raise

    def write_log(self, message: str) -> None:
        """Securely write a log message."""
        if not isinstance(message, str):
            raise ValueError("Message must be a string")

        try:
            # Check file size before writing
            if self._check_file_size():
                self.logger.info(message)
            else:
                self.logger.error("Log file size limit exceeded")
        except Exception as e:
            self.logger.error(f"Failed to write log: {str(e)}")

    def read_log(self) -> Optional[str]:
        """Securely read log file contents."""
        try:
            with open(self.log_file, 'r') as f:
                fcntl.flock(f.fileno(), fcntl.LOCK_SH)
                return f.read()
        except Exception as e:
            self.logger.error(f"Failed to read log: {str(e)}")
            return None

    def _check_file_size(self) -> bool:
        """Check if log file exceeds size limit."""
        try:
            return os.path.getsize(self.log_file) > self.max_size
        except Exception as e:
            self.logger.error(f"Failed to check file size: {str(e)}")
            return False

    def __del__(self):
        """Ensure proper cleanup."""
        try:
            fcntl.flock(self.log_file.fileno(), fcntl.LOCK_UN)
        except Exception as e:
            self.logger.error(f"Failed to unlock log file: {str(e)}")
