from flask import Flask, request, abort
from functools import wraps
import secrets
import logging
from typing import Callable, Optional

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Secure secret key generation
